import { NextResponse } from 'next/server';

const VC_API_BASE_URL =
  process.env.NEXT_PUBLIC_VC_SIM_API_BASE_URL?.replace(/\/$/, '') || 'http://localhost:8000';

export async function GET() {
  try {
    const upstream = await fetch(`${VC_API_BASE_URL}/healthz`, { cache: 'no-store' });
    if (!upstream.ok) {
      return NextResponse.json(
        { status: 'error', llm_router_mode: 'unknown', data_configured: false },
        { status: upstream.status }
      );
    }

    const payload = await upstream.json();
    return NextResponse.json(
      {
        status: 'ok',
        llm_router_mode: payload?.router?.router_mode || 'unknown',
        data_configured: !!payload?.database_configured,
        data_available: !!payload?.database_available,
      },
      { status: 200 }
    );
  } catch (error) {
    return NextResponse.json(
      {
        status: 'error',
        llm_router_mode: 'unknown',
        data_configured: false,
        message: error instanceof Error ? error.message : 'unknown error',
      },
      { status: 502 }
    );
  }
}
